import{_ as s,c as a,o as e,ae as n}from"./chunks/framework.CDjunVez.js";const k=JSON.parse('{"title":"Location","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/locations.md","filePath":"introduction/locations.md"}'),t={name:"introduction/locations.md"};function l(h,i,o,p,c,d){return e(),a("div",null,[...i[0]||(i[0]=[n(`<h1 id="location" tabindex="-1">Location <a class="header-anchor" href="#location" aria-label="Permalink to &quot;Location&quot;">​</a></h1><h2 id="web-page" tabindex="-1">Web page <a class="header-anchor" href="#web-page" aria-label="Permalink to &quot;Web page&quot;">​</a></h2><ul><li><p><code>/home/kiwiweb/default_site/index.html</code>: This is the default index file when you visit the IP address of your VPS.</p></li><li><p><code>/home/linux_user/domain.com/public_html</code>: This is the home directory for each domain. You can create a new directory here and upload your (HTML or PHP) website files.</p></li></ul><h2 id="default-locations" tabindex="-1">Default locations <a class="header-anchor" href="#default-locations" aria-label="Permalink to &quot;Default locations&quot;">​</a></h2><p>Here are the folders on your VPS that Kiwipanel uses:</p><ul><li><p><code>/usr/local/bin/kiwipanel</code>: This is the &quot;root&quot; binary (written in bash) file of Kiwipanel. It is used to start and stop the Kiwipanel service. Sometimes you might use this binary to fix the permissions of the Kiwipanel binary file (written in Golang), if any. Normally everything is fine.</p></li><li><p><code>/opt/kiwipanel</code>: This is the core directory where Kiwipanel is installed. <code>/opt/kiwipanel/{bin, config, data, logs, meta, scripts, ssl, templates}</code>: The binary file, the config file, the logs... of Kiwipanel are all located here.</p></li><li><p><code>/opt/kiwipanel/ssl/panel</code>: Contains the SSL certificate files. After installing you will get two files: kiwipanel.key and kiwipanel.crt. These files are used to secure the panel and this is self-signed certificate (IP:8443).</p></li><li><p><code>/home/kiwiweb/default_site/index.html</code>: This is the default index file when you visit the IP address of your VPS.</p></li><li><p><code>/usr/local/lsws/</code>: This is the location of LiteSpeed Web Server (LSWS) on your VPS. LSWS is the web server that Kiwipanel uses to serve the web interface.</p></li><li><p><code>/usr/local/lsws/conf/httpd_config.conf</code>: This file is the default configuration file for LiteSpeed Web Server (LSWS). It contains the settings for the web server, such as the listening port, the document root, and the SSL certificate. During the process of installation, Kiwipanel will modify this file to include the necessary settings for the web server. At the bottom of this file, you will find the following lines:</p></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># KiwiPanel include (DO NOT REMOVE)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/kiwipanel/config/lsws/config/kiwipanel.conf</span></span></code></pre></div><p>It fundamentally means Kiwipanel will include the configuration file for LSWS in the main configuration file and OVERWRITE/APPEND that configuration at new file located at <code>/opt/kiwipanel/config/lsws/config/kiwipanel.conf</code>.</p><p>In case you care about this design, have a look at <code>https://github.com/kiwipanel/kiwipanel/blob/main/kiwipanel/config/lsws/config/kiwipanel.conf</code> or in our VPS run <code>cat /opt/kiwipanel/config/lsws/config/kiwipanel.conf</code> to see the content of this configuration. Basically it includes two other configuration files.</p><p>First, the <code>include /opt/kiwipanel/config/lsws/config/listeners.conf</code> has the following content:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># KiwiPanel-managed HTTP listener</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">listener</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HTTP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    address</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:80</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    secure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    map</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KiwiPanel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>It sets the port for the HTTP listener to 80. (instead of 8088 as default by OpenLiteSpeed) and it maps to Kiwipanel. Kiwipanel is a virtualhost that is defined in the <code>include /opt/kiwipanel/config/lsws/config/virtualhosts.conf</code> file.</p><p>Second, the file <code>include /opt/kiwipanel/config/lsws/config/virtualhosts.conf</code> has the following content:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Virtual Host: Default IP</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># =========================================================</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">virtualHost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KiwiPanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    vhRoot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">         /opt/kiwipanel/config/lsws/vhosts/KiwiPanel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    configFile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     /opt/kiwipanel/config/lsws/vhosts/KiwiPanel/vhconf.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    allowSymbolLink</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    enableScript</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    restrained</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>It sets config for the virualHost KiwiPanel which turns our to be located at <code>/opt/kiwipanel/config/lsws/vhosts/KiwiPanel/vhconf.conf</code>. <code>vhRoot</code> simply means the root directory of the virtual host.</p><p>The file <code>/opt/kiwipanel/config/lsws/vhosts/KiwiPanel/vhconf.conf</code> has the following content:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># This is the root directory of the virtual host. Inside this folder we have a index.html file. </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># The content of this file is shown when you visit the IP of the #VPS.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docRoot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/kiwiweb/default_site/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">enableGzip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">context</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  allowBrowse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  rewrite</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    RewriteFile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .htaccess</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">index</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  autoIndexURI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /_autoindex/default.php</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  indexFiles</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> index.html</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  autoIndex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  useServer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Now you might realize that the <code>vhRoot</code> is the root directory of the virtual host, and the <code>configFile</code> is the configuration file for the virtual host. We have successfully changed the default port to 80 and mapped it to Kiwipanel and the html directory is located at <code>/home/kiwiweb/default_site/</code>.</p><p>Location of updated panel <code>/var/lib/kiwipanel/update</code></p><p>Mariadb: Installing log: <code>/var/log/kiwipanel-install.log</code></p><p>Mariadb error log: <code>/var/log/mysql/error.log</code></p>`,21)])])}const g=s(t,[["render",l]]);export{k as __pageData,g as default};
